CREATE TABLE public.credit_wallets (org_id UUID NOT NULL PRIMARY KEY, balance INTEGER NOT NULL DEFAULT 0 CHECK (balance >= 0), created_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_at TIMESTAMPTZ NOT NULL DEFAULT now()); ALTER TABLE public.credit_wallets ENABLE ROW LEVEL SECURITY; CREATE POLICY "wallets_members_view" ON public.credit_wallets FOR SELECT USING (public.is_org_member(auth.uid(), org_id)); CREATE TRIGGER trg_credit_wallets_updated BEFORE UPDATE ON public.credit_wallets FOR EACH ROW EXECUTE FUNCTION public.touch_updated_at(); CREATE TABLE public.credit_transactions (id UUID NOT NULL PRIMARY KEY DEFAULT gen_random_uuid(), org_id UUID NOT NULL, kind TEXT NOT NULL CHECK (kind IN ('topup','spend','refund','adjust')), credits INTEGER NOT NULL, naira_amount INTEGER, reference TEXT, pack TEXT, audit_license_id UUID, created_by UUID, created_at TIMESTAMPTZ NOT NULL DEFAULT now()); CREATE INDEX idx_credit_tx_org ON public.credit_transactions (org_id, created_at DESC); CREATE UNIQUE INDEX uq_credit_tx_topup_ref ON public.credit_transactions (reference) WHERE kind = 'topup'; ALTER TABLE public.credit_transactions ENABLE ROW LEVEL SECURITY; CREATE POLICY "credit_tx_members_view" ON public.credit_transactions FOR SELECT USING (public.is_org_member(auth.uid(), org_id)); CREATE OR REPLACE FUNCTION public.topup_credits(_org_id UUID, _credits INTEGER, _naira INTEGER, _reference TEXT, _user_id UUID) RETURNS UUID LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS 'DECLARE tx_id UUID; BEGIN IF _credits <= 0 THEN RAISE EXCEPTION ''credits must be positive''; END IF; IF EXISTS (SELECT 1 FROM public.credit_transactions WHERE kind=''topup'' AND reference=_reference) THEN SELECT id INTO tx_id FROM public.credit_transactions WHERE kind=''topup'' AND reference=_reference LIMIT 1; RETURN tx_id; END IF; INSERT INTO public.credit_wallets (org_id, balance) VALUES (_org_id, _credits) ON CONFLICT (org_id) DO UPDATE SET balance = public.credit_wallets.balance + EXCLUDED.balance, updated_at = now(); INSERT INTO public.credit_transactions (org_id, kind, credits, naira_amount, reference, created_by) VALUES (_org_id, ''topup'', _credits, _naira, _reference, _user_id) RETURNING id INTO tx_id; RETURN tx_id; END;'; CREATE OR REPLACE FUNCTION public.spend_credits_for_pack(_org_id UUID, _pack TEXT) RETURNS UUID LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS 'DECLARE cost INTEGER; naira INTEGER; current_balance INTEGER; new_license_id UUID; BEGIN IF NOT (public.has_role(auth.uid(), _org_id, ''owner''::app_role) OR public.has_role(auth.uid(), _org_id, ''admin''::app_role) OR public.has_role(auth.uid(), _org_id, ''lead_auditor''::app_role)) THEN RAISE EXCEPTION ''not authorised to spend credits for this organisation''; END IF; CASE _pack WHEN ''iso9001'' THEN cost:=1; naira:=5000; WHEN ''iso14001'' THEN cost:=1; naira:=5000; WHEN ''iso45001'' THEN cost:=1; naira:=5000; WHEN ''iso27001'' THEN cost:=1; naira:=5000; WHEN ''hse'' THEN cost:=2; naira:=10000; WHEN ''ims'' THEN cost:=3; naira:=15000; ELSE RAISE EXCEPTION ''unknown audit pack: %'', _pack; END CASE; SELECT balance INTO current_balance FROM public.credit_wallets WHERE org_id=_org_id FOR UPDATE; IF current_balance IS NULL THEN RAISE EXCEPTION ''no wallet for organisation''; END IF; IF current_balance < cost THEN RAISE EXCEPTION ''insufficient credits''; END IF; UPDATE public.credit_wallets SET balance = balance - cost, updated_at = now() WHERE org_id=_org_id; INSERT INTO public.audit_licenses (org_id, pack, paid_amount_ngn, paystack_ref, active) VALUES (_org_id, _pack, naira, ''wallet:'' || gen_random_uuid()::text, true) RETURNING id INTO new_license_id; INSERT INTO public.credit_transactions (org_id, kind, credits, naira_amount, pack, audit_license_id, created_by) VALUES (_org_id, ''spend'', -cost, naira, _pack, new_license_id, auth.uid()); RETURN new_license_id; END;'; INSERT INTO public.credit_wallets (org_id, balance) SELECT id, 0 FROM public.organizations ON CONFLICT (org_id) DO NOTHING; CREATE OR REPLACE FUNCTION public.create_wallet_for_org() RETURNS TRIGGER LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS 'BEGIN INSERT INTO public.credit_wallets (org_id, balance) VALUES (NEW.id, 0) ON CONFLICT (org_id) DO NOTHING; RETURN NEW; END;'; CREATE TRIGGER trg_org_create_wallet AFTER INSERT ON public.organizations FOR EACH ROW EXECUTE FUNCTION public.create_wallet_for_org();